loader.js.content:
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

export async function registerCommands(bot) {
  const dir = path.dirname(fileURLToPath(import.meta.url));

  const commandFiles = fs
    .readdirSync(dir)
    .filter((file) => file.endsWith(".js") && file !== "loader.js" && !file.startsWith("_"));

  for (const file of commandFiles) {
    const url = pathToFileURL(path.join(dir, file)).href;
    const mod = await import(url);

    const handler = mod?.default || mod?.register;
    if (typeof handler === "function") {
      await handler(bot);
    } else {
      console.warn("[commands] skipped (no default/register export)", { file });
    }
  }
}

mood.js.content:
import { InlineKeyboard } from "grammy";
import { cfg } from "../lib/config.js";
import { safeReply } from "../lib/send.js";
import { getUser, updateUser, addHistory } from "../lib/userStore.js";
import { generateMotivation } from "../features/generation.js";
import { makeItemId } from "../features/items.js";

const MOODS = ["Great", "Okay", "Stressed", "Sad", "Unmotivated", "Angry", "Anxious"];

export default function register(bot) {
  bot.command("mood", async (ctx) => {
    const kb = new InlineKeyboard();
    for (const m of MOODS) {
      kb.text(m, "mood:set:" + encodeURIComponent(m));
      kb.row();
    }
    await safeReply(ctx, "How are you feeling right now?", { reply_markup: kb });
  });

  bot.callbackQuery(/^(mood:set:)/, async (ctx) => {
    const uid = ctx.from?.id;
    const data = String(ctx.callbackQuery?.data || "");
    if (!uid) return;

    await ctx.answerCallbackQuery();

    const mood = decodeURIComponent(data.slice("mood:set:".length));

    if (!cfg.MONGODB_URI) {
      await safeReply(ctx, "I can respond, but I can’t store mood without MongoDB (MONGODB_URI).");
    } else {
      await updateUser(cfg.MONGODB_URI, uid, { lastMood: mood, lastMoodAt: new Date() });
    }

    if (!cfg.COOKMYBOTS_AI_ENDPOINT || !cfg.COOKMYBOTS_AI_KEY) {
      await safeReply(ctx, `Got it: ${mood}. AI isn’t configured yet, so I can’t generate a tailored message.`);
      return;
    }

    const user = await getUser(cfg.MONGODB_URI, uid);
    const result = await generateMotivation({ cfg, user, extraUserText: `My mood is: ${mood}` });
    if (!result.ok) {
      await safeReply(ctx, result.text);
      return;
    }

    const itemId = makeItemId();
    if (cfg.MONGODB_URI) {
      await updateUser(cfg.MONGODB_URI, uid, { lastItem: { itemId, type: "motivate", text: result.text } });
      await addHistory(cfg.MONGODB_URI, uid, { itemId, type: "motivate", text: result.text });
    }

    await safeReply(ctx, result.text);
  });
}

motivate.js.content:
import { InlineKeyboard } from "grammy";
import { cfg } from "../lib/config.js";
import { safeReply } from "../lib/send.js";
import { getUser, updateUser, addHistory } from "../lib/userStore.js";
import { generateMotivation } from "../features/generation.js";
import { makeItemId } from "../features/items.js";
import { tryAcquire, lockMessage } from "../features/locks.js";

export default function register(bot) {
  bot.command("motivate", async (ctx) => {
    const uid = ctx.from?.id;
    const chatId = ctx.chat?.id;
    if (!uid || !chatId) return;

    const lock = tryAcquire(chatId);
    if (!lock.ok) {
      await safeReply(ctx, lockMessage(lock.reason));
      return;
    }

    try {
      if (!cfg.COOKMYBOTS_AI_ENDPOINT || !cfg.COOKMYBOTS_AI_KEY) {
        await safeReply(ctx, "AI isn’t configured yet. Set COOKMYBOTS_AI_ENDPOINT and COOKMYBOTS_AI_KEY.");
        return;
      }

      const user = await getUser(cfg.MONGODB_URI, uid);
      const result = await generateMotivation({ cfg, user });

      if (!result.ok) {
        await safeReply(ctx, result.text);
        return;
      }

      const itemId = makeItemId();
      if (cfg.MONGODB_URI) {
        await updateUser(cfg.MONGODB_URI, uid, { lastItem: { itemId, type: "motivate", text: result.text } });
        await addHistory(cfg.MONGODB_URI, uid, { itemId, type: "motivate", text: result.text });
      }

      const kb = new InlineKeyboard()
        .text("Save", "fav:save:" + encodeURIComponent(itemId))
        .text("Another", "gen:motivate")
        .row()
        .text("Change categories", "fav:change_cats");

      await safeReply(ctx, result.text, { reply_markup: kb });
    } finally {
      lock.release();
    }
  });
}

remind.js.content:
import { InlineKeyboard } from "grammy";
import { cfg } from "../lib/config.js";
import { safeReply } from "../lib/send.js";
import { updateUser, parseTimeHHMM, isValidIanaTimezone } from "../lib/userStore.js";
import { setRemindState, getRemindState, clearRemindState } from "../features/state.js";

export default function register(bot) {
  bot.command("remind", async (ctx) => {
    const uid = ctx.from?.id;
    if (!uid) return;

    if (!cfg.MONGODB_URI) {
      await safeReply(ctx, "Reminders need MongoDB (MONGODB_URI). Right now I’m running in stateless mode.");
      return;
    }

    setRemindState(uid, { step: "time" });
    await safeReply(ctx, "What time should I remind you? Reply with HH:MM (24h), for example 08:30");
  });

  bot.on("message:text", async (ctx, next) => {
    const uid = ctx.from?.id;
    const text = String(ctx.message?.text || "").trim();
    if (!uid) return next();
    if (text.startsWith("/")) return next();

    const rs = getRemindState(uid);
    if (!rs) return next();

    if (!cfg.MONGODB_URI) {
      clearRemindState(uid);
      return next();
    }

    if (rs.step === "time") {
      const parsed = parseTimeHHMM(text);
      if (!parsed) {
        await safeReply(ctx, "That doesn’t look like HH:MM. Example: 21:15");
        return;
      }
      setRemindState(uid, { step: "timezone", reminderTime: text });
      await safeReply(ctx, "Timezone? Send an IANA name like Europe/London. Or reply 'UTC' to use UTC.");
      return;
    }

    if (rs.step === "timezone") {
      const tzRaw = text === "UTC" ? "UTC" : text;
      const tz = isValidIanaTimezone(tzRaw) ? tzRaw : "UTC";
      setRemindState(uid, { step: "type", reminderTime: rs.reminderTime, timezone: tz });

      const kb = new InlineKeyboard()
        .text("Motivation", "rem:type:Motivation")
        .text("Tip", "rem:type:Tip")
        .row()
        .text("Mixed", "rem:type:Mixed");

      await safeReply(ctx, `Reminder type? (Time: ${rs.reminderTime}, TZ: ${tz})`, { reply_markup: kb });
      return;
    }

    return next();
  });

  bot.callbackQuery(/^(rem:type:)/, async (ctx) => {
    const uid = ctx.from?.id;
    if (!uid) return;
    await ctx.answerCallbackQuery();

    if (!cfg.MONGODB_URI) {
      await safeReply(ctx, "Reminders need MongoDB (MONGODB_URI). Right now I’m running in stateless mode.");
      return;
    }

    const data = String(ctx.callbackQuery?.data || "");
    const type = data.slice("rem:type:".length);

    const rs = getRemindState(uid);
    if (!rs?.reminderTime) {
      await safeReply(ctx, "Please run /remind to configure reminders.");
      return;
    }

    await updateUser(cfg.MONGODB_URI, uid, {
      remindersEnabled: true,
      reminderTime: rs.reminderTime,
      timezone: rs.timezone || "UTC",
      reminderType: type === "Motivation" || type === "Tip" || type === "Mixed" ? type : "Mixed",
      lastReminderSentOn: "",
    });

    clearRemindState(uid);
    await safeReply(ctx, "Reminders enabled. Use /remind_off to disable.");
  });
}

