import { InlineKeyboard } from "grammy";
import { safeReply } from "../lib/send.js";
import { cfg } from "../lib/config.js";
import { getUser, updateUser, DEFAULT_CATEGORIES } from "../lib/userStore.js";
import { buildCategoriesKeyboard } from "../features/categoriesUi.js";
import { setOnboardingState, getOnboardingState, clearOnboardingState, setRemindState, clearRemindState } from "../features/state.js";
import { parseTimeHHMM, isValidIanaTimezone } from "../lib/userStore.js";

export default function register(bot) {
  bot.command("start", async (ctx) => {
    const uid = ctx.from?.id;
    if (!uid) return;

    if (cfg.MONGODB_URI) {
      await getUser(cfg.MONGODB_URI, uid);
    }

    await safeReply(
      ctx,
      "Hi. I can send motivational messages and practical life tips tailored to what you care about.\n\nFirst, pick the categories you want:",
      { reply_markup: buildCategoriesKeyboard((await getUser(cfg.MONGODB_URI, uid))?.categories || DEFAULT_CATEGORIES) }
    );

    setOnboardingState(uid, { step: "categories" });

    const kb = new InlineKeyboard().text("Yes", "onb:remind_yes").text("No", "onb:remind_no");
    await safeReply(ctx, "Do you want daily reminders?", { reply_markup: kb });
  });

  bot.callbackQuery("onb:remind_yes", async (ctx) => {
    const uid = ctx.from?.id;
    if (!uid) return;
    await ctx.answerCallbackQuery();

    if (!cfg.MONGODB_URI) {
      await safeReply(ctx, "Daily reminders need MongoDB (MONGODB_URI). Right now I’m running in stateless mode.");
      return;
    }

    setRemindState(uid, { step: "time" });
    await safeReply(ctx, "What time should I remind you? Reply with HH:MM (24h), for example 08:30");
  });

  bot.callbackQuery("onb:remind_no", async (ctx) => {
    await ctx.answerCallbackQuery();
    await safeReply(ctx, "No problem. You can set reminders later with /remind.\n\nTry /motivate or /tip anytime.");
  });

  bot.on("message:text", async (ctx, next) => {
    const uid = ctx.from?.id;
    const text = String(ctx.message?.text || "").trim();
    if (!uid) return next();
    if (text.startsWith("/")) return next();

    const rs = getRemindState(uid);
    if (!rs) return next();

    if (!cfg.MONGODB_URI) {
      clearRemindState(uid);
      return next();
    }

    if (rs.step === "time") {
      const parsed = parseTimeHHMM(text);
      if (!parsed) {
        await safeReply(ctx, "That doesn’t look like HH:MM. Example: 21:15");
        return;
      }
      setRemindState(uid, { step: "timezone", reminderTime: text });
      await safeReply(ctx, "What timezone are you in? Send an IANA name like Europe/London. Or reply 'UTC' to use UTC.");
      return;
    }

    if (rs.step === "timezone") {
      const tzRaw = text === "UTC" ? "UTC" : text;
      const tz = isValidIanaTimezone(tzRaw) ? tzRaw : "UTC";
      setRemindState(uid, { step: "type", reminderTime: rs.reminderTime, timezone: tz });

      const kb = new InlineKeyboard()
        .text("Motivation", "onb:type:Motivation")
        .text("Tip", "onb:type:Tip")
        .row()
        .text("Mixed", "onb:type:Mixed");

      await safeReply(ctx, `Reminder type? (Time: ${rs.reminderTime}, TZ: ${tz})`, { reply_markup: kb });
      return;
    }

    return next();
  });

  bot.callbackQuery(/^(onb:type:)/, async (ctx) => {
    const uid = ctx.from?.id;
    if (!uid) return;
    await ctx.answerCallbackQuery();

    if (!cfg.MONGODB_URI) {
      await safeReply(ctx, "Reminders need MongoDB (MONGODB_URI). Right now I’m running in stateless mode.");
      return;
    }

    const data = String(ctx.callbackQuery?.data || "");
    const type = data.slice("onb:type:".length);

    const rs = getRemindState(uid);
    if (!rs?.reminderTime) {
      await safeReply(ctx, "Please run /remind to configure reminders.");
      return;
    }

    await updateUser(cfg.MONGODB_URI, uid, {
      remindersEnabled: true,
      reminderTime: rs.reminderTime,
      timezone: rs.timezone || "UTC",
      reminderType: type === "Motivation" || type === "Tip" || type === "Mixed" ? type : "Mixed",
      lastReminderSentOn: "",
    });

    clearRemindState(uid);
    clearOnboardingState(uid);

    await safeReply(ctx, "Done. You’ll get one reminder per day at that time. You can change it anytime with /remind, or stop with /remind_off.");
  });
}

tip.js.content:
import { InlineKeyboard } from "grammy";
import { cfg } from "../lib/config.js";
import { safeReply } from "../lib/send.js";
import { getUser, updateUser, addHistory } from "../lib/userStore.js";
import { generateTip } from "../features/generation.js";
import { makeItemId } from "../features/items.js";
import { tryAcquire, lockMessage } from "../features/locks.js";

export default function register(bot) {
  bot.command("tip", async (ctx) => {
    const uid = ctx.from?.id;
    const chatId = ctx.chat?.id;
    if (!uid || !chatId) return;

    const lock = tryAcquire(chatId);
    if (!lock.ok) {
      await safeReply(ctx, lockMessage(lock.reason));
      return;
    }

    try {
      if (!cfg.COOKMYBOTS_AI_ENDPOINT || !cfg.COOKMYBOTS_AI_KEY) {
        await safeReply(ctx, "AI isn’t configured yet. Set COOKMYBOTS_AI_ENDPOINT and COOKMYBOTS_AI_KEY.");
        return;
      }

      const user = await getUser(cfg.MONGODB_URI, uid);
      const result = await generateTip({ cfg, user });

      if (!result.ok) {
        await safeReply(ctx, result.text);
        return;
      }

      const itemId = makeItemId();
      if (cfg.MONGODB_URI) {
        await updateUser(cfg.MONGODB_URI, uid, { lastItem: { itemId, type: "tip", text: result.text } });
        await addHistory(cfg.MONGODB_URI, uid, { itemId, type: "tip", text: result.text });
      }

      const kb = new InlineKeyboard()
        .text("Save", "fav:save:" + encodeURIComponent(itemId))
        .text("Another", "gen:tip")
        .row()
        .text("Change categories", "fav:change_cats");

      await safeReply(ctx, result.text, { reply_markup: kb });
    } finally {
      lock.release();
    }
  });
}

callbacks.js.content:
import { InlineKeyboard } from "grammy";
import { safeReply } from "../lib/send.js";
import { safeErr } from "../lib/safeErr.js";
import {
  getUser,
  updateUser,
  addFavorite,
  removeFavorite,
  DEFAULT_CATEGORIES,
  allowedCategories,
} from "../lib/userStore.js";
import { buildCategoriesKeyboard } from "./categoriesUi.js";
import { makeItemId } from "./items.js";
import { generateMotivation, generateTip } from "./generation.js";

function parseData(prefix, data) {
  const s = String(data || "");
  if (!s.startsWith(prefix)) return null;
  return s.slice(prefix.length);
}

export function registerCallbacks(bot, { cfg }) {
  bot.callbackQuery(/^(cat:toggle:|cat:done|onb:|fav:|gen:|favpage:)/, async (ctx) => {
    const data = ctx.callbackQuery?.data || "";
    const uid = ctx.from?.id;
    if (!uid) return;

    try {
      if (data.startsWith("cat:toggle:")) {
        const raw = decodeURIComponent(parseData("cat:toggle:", data) || "");
        const user = await getUser(cfg.MONGODB_URI, uid);
        const current = new Set((user?.categories || DEFAULT_CATEGORIES).map((c) => String(c)));
        if (current.has(raw)) current.delete(raw);
        else current.add(raw);

        const updated = Array.from(current).filter((c) => allowedCategories().includes(c));
        if (!cfg.MONGODB_URI) {
          await ctx.answerCallbackQuery({ text: "MongoDB not set. Preferences aren’t saved." });
        } else {
          await updateUser(cfg.MONGODB_URI, uid, { categories: updated.length ? updated : DEFAULT_CATEGORIES });
          await ctx.answerCallbackQuery({ text: "Updated" });
        }

        const u2 = await getUser(cfg.MONGODB_URI, uid);
        const kb = buildCategoriesKeyboard(u2?.categories || DEFAULT_CATEGORIES);
        await ctx.editMessageReplyMarkup({ reply_markup: kb });
        return;
      }

      if (data === "cat:done") {
        await ctx.answerCallbackQuery();
        await safeReply(ctx, "All set. Try /motivate or /tip whenever you want.");
        return;
      }

      if (data.startsWith("gen:")) {
        const which = parseData("gen:", data);
        await ctx.answerCallbackQuery();
        if (which !== "motivate" && which !== "tip") return;

        const user = await getUser(cfg.MONGODB_URI, uid);
        const result = which === "motivate"
          ? await generateMotivation({ cfg, user })
          : await generateTip({ cfg, user });

        if (!result.ok) {
          await safeReply(ctx, result.text);
          return;
        }

        const itemId = makeItemId();
        if (cfg.MONGODB_URI) {
          await updateUser(cfg.MONGODB_URI, uid, { lastItem: { itemId, type: which, text: result.text } });
        }

        const kb = new InlineKeyboard()
          .text("Save", "fav:save:" + encodeURIComponent(itemId))
          .text("Another", "gen:" + which)
          .row()
          .text("Change categories", "fav:change_cats");

        await safeReply(ctx, result.text, { reply_markup: kb });
        return;
      }

      if (data === "fav:change_cats") {
        await ctx.answerCallbackQuery();
        const user = await getUser(cfg.MONGODB_URI, uid);
        const kb = buildCategoriesKeyboard(user?.categories || DEFAULT_CATEGORIES);
        await safeReply(ctx, "Pick your categories:", { reply_markup: kb });
        return;
      }

      if (data.startsWith("fav:save:")) {
        await ctx.answerCallbackQuery();
        if (!cfg.MONGODB_URI) {
          await safeReply(ctx, "Favorites need MongoDB (MONGODB_URI). Right now I’m running in stateless mode.");
          return;
        }

        const user = await getUser(cfg.MONGODB_URI, uid);
        const last = user?.lastItem;
        if (!last?.text) {
          await safeReply(ctx, "I don’t have a recent item to save. Try /motivate or /tip first.");
          return;
        }

        const res = await addFavorite(cfg.MONGODB_URI, uid, {
          itemId: String(last.itemId || ""),
          type: String(last.type || ""),
          text: String(last.text || ""),
        });

        if (res.ok) await safeReply(ctx, "Saved. Use /favorites to see your saved items.");
        else await safeReply(ctx, "Couldn’t save that right now. Try again.");
        return;
      }

      if (data.startsWith("fav:remove:")) {
        await ctx.answerCallbackQuery();
        if (!cfg.MONGODB_URI) {
          await safeReply(ctx, "Favorites need MongoDB (MONGODB_URI). Right now I’m running in stateless mode.");
          return;
        }
        const itemId = decodeURIComponent(parseData("fav:remove:", data) || "");
        await removeFavorite(cfg.MONGODB_URI, uid, itemId);
        await safeReply(ctx, "Removed.");
        return;
      }

      if (data.startsWith("favpage:")) {
        await ctx.answerCallbackQuery();
        // pagination handled by /favorites command (callback only nudges user)
        await safeReply(ctx, "Use /favorites again to refresh the list.");
        return;
      }

      if (data.startsWith("onb:")) {
        await ctx.answerCallbackQuery();
        // onboarding callbacks are handled in /start command module
        return;
      }
    } catch (e) {
      console.error("[callbacks] error", { err: safeErr(e) });
      try {
        await ctx.answerCallbackQuery({ text: "Something went wrong" });
      } catch {
        // ignore
      }
    }
  });
}

categoriesUi.js.content:
import { InlineKeyboard } from "grammy";
import { allowedCategories } from "../lib/userStore.js";

export function buildCategoriesKeyboard(selected) {
  const sel = new Set((selected || []).map((s) => String(s)));
  const kb = new InlineKeyboard();

  for (const c of allowedCategories()) {
    const mark = sel.has(c) ? "✅ " : "☑️ ";
    kb.text(mark + c, "cat:toggle:" + encodeURIComponent(c));
    kb.row();
  }

  kb.row();
  kb.text("Done", "cat:done");
  return kb;
}

generation.js.content:
import { aiChat, extractGatewayChatContent } from "../lib/ai.js";
import { buildBotProfile } from "../lib/botProfile.js";
import { safeErr } from "../lib/safeErr.js";

function joinCats(cats) {
  const arr = Array.isArray(cats) ? cats : [];
  const cleaned = arr.map((c) => String(c).trim()).filter(Boolean);
  return cleaned.length ? cleaned.join(", ") : "(none)";
}

function moodLine(mood) {
  const m = String(mood || "").trim();
  if (!m) return "Mood: unknown";
  return "Mood: " + m;
}

export async function generateMotivation({ cfg, user, extraUserText = "" }) {
  const profile = buildBotProfile();
  const cats = joinCats(user?.categories);
  const mood = moodLine(user?.lastMood);

  const system = [
    profile,
    "",
    "You generate motivational messages and life tips.",
    "Output rules:",
    "1) Keep it concise: 2–5 sentences.",
    "2) Supportive and practical. No shame, no moralizing.",
    "3) Add an optional one-line actionable step prefixed with: Action: ",
    "4) No medical or legal advice.",
    "5) If the user text suggests self-harm/crisis, respond with a supportive crisis-safe message encouraging contacting local emergency services or a trusted person.",
  ].join("\n");

  const userPrompt = [
    "User preferences:",
    "Categories: " + cats,
    mood,
    extraUserText ? ("User context: " + String(extraUserText).slice(0, 800)) : "",
    "",
    "Write one motivational message tailored to the user.",
  ]
    .filter(Boolean)
    .join("\n");

  const res = await aiChat(
    cfg,
    {
      messages: [
        { role: "system", content: system },
        { role: "user", content: userPrompt },
      ],
      meta: { platform: "telegram", feature: "motivate" },
    },
    { retries: Number(cfg?.AI_MAX_RETRIES || 2) }
  );

  if (!res.ok) {
    console.error("[motivate] ai failed", { err: res.error || safeErr(res) });
    return { ok: false, text: "I couldn’t generate something right now. Try again in a moment." };
  }

  const text = extractGatewayChatContent(res.json);
  if (!text) {
    return { ok: false, text: "I didn’t get a valid response back. Try again." };
  }

  return { ok: true, text };
}

export async function generateTip({ cfg, user, extraUserText = "" }) {
  const profile = buildBotProfile();
  const cats = joinCats(user?.categories);
  const mood = moodLine(user?.lastMood);

  const system = [
    profile,
    "",
    "You generate practical life tips.",
    "Output rules:",
    "1) Keep it concise. Short intro + 2–4 bullet steps.",
    "2) Use simple hyphen bullets.",
    "3) Non-preachy, realistic, kind.",
    "4) No medical or legal advice.",
    "5) If the user text suggests self-harm/crisis, respond with a supportive crisis-safe message encouraging contacting local emergency services or a trusted person.",
  ].join("\n");

  const userPrompt = [
    "User preferences:",
    "Categories: " + cats,
    mood,
    extraUserText ? ("User context: " + String(extraUserText).slice(0, 800)) : "",
    "",
    "Write one practical tip tailored to the user.",
  ]
    .filter(Boolean)
    .join("\n");

  const res = await aiChat(
    cfg,
    {
      messages: [
        { role: "system", content: system },
        { role: "user", content: userPrompt },
      ],
      meta: { platform: "telegram", feature: "tip" },
    },
    { retries: Number(cfg?.AI_MAX_RETRIES || 2) }
  );

  if (!res.ok) {
    console.error("[tip] ai failed", { err: res.error || safeErr(res) });
    return { ok: false, text: "I couldn’t generate a tip right now. Try again in a moment." };
  }

  const text = extractGatewayChatContent(res.json);
  if (!text) {
    return { ok: false, text: "I didn’t get a valid response back. Try again." };
  }

  return { ok: true, text };
}

items.js.content:
import crypto from "node:crypto";

export function makeItemId() {
  return crypto.randomBytes(9).toString("hex");
}

export function snippet(s, max = 90) {
  const t = String(s || "").replace(/\s+/g, " ").trim();
  if (t.length <= max) return t;
  return t.slice(0, max - 1) + "…";
}

export function formatHistoryItem(row) {
  const when = row?.createdAt ? new Date(row.createdAt) : null;
  const ts = when ? when.toISOString().replace("T", " ").slice(0, 16) + "Z" : "";
  const sn = snippet(row?.text || "", 110);
  const type = String(row?.type || "item");
  return `${ts} [${type}] ${sn}`.trim();
}

export function extractCrisisSignal(text) {
  const t = String(text || "").toLowerCase();
  const signals = [
    "suicide",
    "kill myself",
    "end it",
    "self harm",
    "self-harm",
    "hurt myself",
    "want to die",
  ];
  return signals.some((s) => t.includes(s));
}

export function crisisResponse() {
  return [
    "I’m really sorry you’re feeling this way.",
    "If you might hurt yourself or you’re in immediate danger, please contact your local emergency services right now.",
    "If you can, reach out to someone you trust (a friend, family member, or someone nearby) and tell them what’s going on.",
    "If you want, tell me what’s happening in a few words, and I can offer a small, non-clinical grounding step too.",
  ].join("\n");
}

